#include <stdio.h>
#include <stdlib.h>

#define MAX_FRAMES 10
#define MAX_PAGES 20

typedef struct {
    int page_id;
    int valid;
} Frame;

int page_faults = 0;
Frame frames[MAX_FRAMES];

// Check if page is in memory
int isPageInMemory(int page) {
    for (int i = 0; i < MAX_FRAMES; i++) {
        if (frames[i].valid && frames[i].page_id == page)
            return 1;
    }
    return 0;
}

// Simple FIFO page replacement
void handlePageFault(int page) {
    // Find first empty frame or replace using FIFO
    static int hand = 0;

    // If all frames full, replace oldest
    for (int i = 0; i < MAX_FRAMES; i++) {
        if (!frames[i].valid) {
            frames[i].page_id = page;
            frames[i].valid = 1;
            page_faults++;
            return;
        }
    }

    // Replace oldest (FIFO)
    frames[hand].page_id = page;
    hand = (hand + 1) % MAX_FRAMES;
    page_faults++;
}

// Simulate thrashing by processing reference string
void simulateThrashing(int ref_string[], int ref_len) {
    printf("Simulating with %d frames...\n", MAX_FRAMES);

    for (int i = 0; i < ref_len; i++) {
        if (!isPageInMemory(ref_string[i])) {
            handlePageFault(ref_string[i]);
            printf("Page fault at reference %d\n", ref_string[i]);
        }
    }

    printf("Total page faults: %d\n", page_faults);
    printf("Fault rate: %.2f%%\n", (float)page_faults/ref_len * 100);

    if ((float)page_faults/ref_len > 0.5)
        printf("WARNING: System is THRASHING!\n");
}

int main() {
    int reference[] = {1, 2, 3, 4, 1, 2, 5, 1, 2, 3, 4, 5};
    int length = sizeof(reference) / sizeof(reference[0]);

    simulateThrashing(reference, length);
    return 0;
}

import java.util.*;

public class ThrashingController {
    private List<Process> activeProcesses;
    private List<Process> suspendedProcesses;
    private int totalFrames;
    private int availableFrames;

    public ThrashingController(int totalFrames) {
        this.totalFrames = totalFrames;
        this.availableFrames = totalFrames;
        this.activeProcesses = new ArrayList<>();
        this.suspendedProcesses = new ArrayList<>();
    }

    public void monitorAndControl() {
        for (Process p : activeProcesses) {
            double faultRate = p.getPageFaultRate();

            if (faultRate > 0.7) {
                // High fault rate - thrashing detected
                if (availableFrames > p.getAllocatedFrames()) {
                    allocateMoreFrames(p);
                } else {
                    // Must suspend another process first
                    suspendLowestPriorityProcess();
                    allocateMoreFrames(p);
                }
            }
        }
    }

    private void suspendLowestPriorityProcess() {
        Process lowest = Collections.min(activeProcesses, 
            Comparator.comparingInt(Process::getPriority));

        activeProcesses.remove(lowest);
        suspendedProcesses.add(lowest);
        availableFrames += lowest.getAllocatedFrames();
        lowest.suspend();

        System.out.println("Suspended process: " + lowest.getPid());
    }

    private void allocateMoreFrames(Process p) {
        int current = p.getAllocatedFrames();
        int needed = current + 5; // Add 5 more frames
        availableFrames -= 5;
        p.setAllocatedFrames(needed);
    }

    public void resumeProcess(Process p) {
        if (availableFrames >= p.getMinFrames()) {
            suspendedProcesses.remove(p);
            activeProcesses.add(p);
            availableFrames -= p.getMinFrames();
            p.setAllocatedFrames(p.getMinFrames());
            p.resume();
        }
    }
}

class Process {
    private int pid;
    private int allocatedFrames;
    private double pageFaultRate;
    private int priority;

    public int getPageFaultRate() { return pageFaultRate; }
    public int getAllocatedFrames() { return allocatedFrames; }
    public void setAllocatedFrames(int f) { allocatedFrames = f; }
    public int getPriority() { return priority; }
    public int getPid() { return pid; }
    public int getMinFrames() { return 10; }
    public void suspend() { /* Save state to disk */ }
    public void resume() { /* Restore state from disk */ }
}
